// ============================================================================
// VALIDATE INPUT
// ============================================================================

let body = $input.first().json.body || $input.first().json || {};

if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch(e) { throw new Error('Invalid JSON in request body'); }
}

const contractId = body.contract_id || body.contractId;
const scheduleId = body.schedule_id || body.scheduleId;

if (!contractId) throw new Error('contract_id is required');
if (!scheduleId) throw new Error('schedule_id is required');

console.log('=== CHECK SCHEDULE COMPLETENESS ===');
console.log('Contract ID:', contractId);
console.log('Schedule ID:', scheduleId);

return { json: { contractId, scheduleId } };

// ============================================================================
// MARK PROCESSING + PREPARE PROMPT
// ============================================================================

const schedule = $('Get Schedule Data').first().json;
const templateRows = $('Get Checklist Templates').all().map(item => item.json);

if (!schedule || !schedule.schedule_id) {
  throw new Error('Schedule not found');
}

const scheduleText = schedule.extracted_text || schedule.summary || '';
if (!scheduleText) {
  throw new Error('Schedule has no extracted text or summary');
}

// If no templates, return empty result (no questions to check)
if (!templateRows || templateRows.length === 0) {
  // Return special marker so we skip the Claude call
  return {
    json: {
      skipClaude: true,
      contractId: schedule.contract_id,
      scheduleId: schedule.schedule_id,
      scheduleType: schedule.schedule_type,
      checklistResults: [],
      checklistScore: null,
    }
  };
}

// Build questions list for Claude
const questions = templateRows.map((t, i) => ({
  index: i + 1,
  template_item_id: t.template_item_id,
  question: t.check_question,
  category: t.check_category,
  importance: t.importance_level,
}));

const questionsText = questions.map(q =>
  `${q.index}. [${q.category.toUpperCase()}] ${q.question}`
).join('\n');

const systemPrompt = `You are CLARENCE — a contract schedule completeness analyst.

You will be given the text of a contract schedule and a set of checklist questions. For each question, determine whether the schedule addresses that item.

RESPONSE RULES:
1. For each question, respond with:
   - "present" — the schedule clearly addresses this item
   - "absent" — the schedule does not address this item at all
   - "partial" — the schedule mentions it but incompletely or ambiguously
2. Provide a brief evidence quote (max 100 chars) from the schedule text supporting your answer
3. Provide a confidence score (0.0-1.0) for each answer

OUTPUT FORMAT — return ONLY valid JSON (no markdown backticks):
{
  "results": [
    {
      "question_index": 1,
      "result": "present",
      "evidence": "The Provider shall maintain availability of 99.5%...",
      "confidence": 0.95
    }
  ]
}`;

const userPrompt = `Analyse this ${schedule.schedule_type.replace(/_/g, ' ')} schedule and answer each checklist question.

SCHEDULE: ${schedule.schedule_label}
CONTRACT: ${schedule.contract_name || 'Unknown'}

---
${scheduleText}
---

CHECKLIST QUESTIONS:
${questionsText}

For each question, determine if the item is present, absent, or partial. Provide evidence and confidence.

Return ONLY the JSON object.`;

const claudeRequestBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4000,
  temperature: 0,
  system: systemPrompt,
  messages: [
    { role: 'user', content: userPrompt }
  ]
};

return {
  json: {
    skipClaude: false,
    contractId: schedule.contract_id,
    scheduleId: schedule.schedule_id,
    scheduleType: schedule.schedule_type,
    questions,
    claudeRequestBody,
  }
};

// ============================================================================
// PROCESS CLAUDE CHECKLIST RESPONSE
// ============================================================================

const prepData = $('Prepare Checklist Prompt').first().json;
const claudeResponse = $input.first().json;

const responseText = claudeResponse.content?.[0]?.text || claudeResponse.text || '';

if (!responseText) {
  throw new Error('Empty response from Claude API. Response: ' + JSON.stringify(claudeResponse).substring(0, 500));
}

let jsonStr = responseText.trim();

// Strip markdown code fences if present
if (jsonStr.includes('```json')) {
  jsonStr = jsonStr.split('```json')[1].split('```')[0].trim();
} else if (jsonStr.includes('```')) {
  jsonStr = jsonStr.split('```')[1].split('```')[0].trim();
}

if (!jsonStr.startsWith('{')) {
  const jsonMatch = jsonStr.match(/\{[\s\S]*\}/);
  if (jsonMatch) jsonStr = jsonMatch[0];
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error('Failed to parse Claude response: ' + e.message + '. Preview: ' + responseText.substring(0, 500));
}

const VALID_RESULTS = ['present', 'absent', 'partial'];
const questions = prepData.questions;

// Map Claude results back to template items
const checklistResults = (parsed.results || []).map(r => {
  const qIdx = (r.question_index || r.index) - 1;
  const question = questions[qIdx];
  if (!question) return null;

  return {
    template_item_id: question.template_item_id,
    check_question: question.question,
    check_category: question.category,
    check_result: VALID_RESULTS.includes(r.result) ? r.result : 'unchecked',
    ai_evidence: (r.evidence || '').substring(0, 500),
    ai_confidence: Math.max(0, Math.min(1, r.confidence || 0.5)),
  };
}).filter(Boolean);

// Calculate completeness score
const totalWeight = questions.reduce((sum, q) => sum + q.importance, 0);
let earnedWeight = 0;
for (const result of checklistResults) {
  const question = questions.find(q => q.template_item_id === result.template_item_id);
  if (!question) continue;
  if (result.check_result === 'present') earnedWeight += question.importance;
  else if (result.check_result === 'partial') earnedWeight += question.importance * 0.5;
}
const checklistScore = totalWeight > 0 ? Math.round((earnedWeight / totalWeight) * 100) : null;

console.log('Checklist results:', checklistResults.length);
console.log('Score:', checklistScore + '%');

return {
  json: {
    contractId: prepData.contractId,
    scheduleId: prepData.scheduleId,
    scheduleType: prepData.scheduleType,
    checklistResults,
    checklistScore,
  }
};

