-- Clear previous checklist results for this schedule
DELETE FROM contract_schedule_checklist WHERE schedule_id = $1::uuid;

-- Insert new results
{{ $json.checklistResults.length > 0 ? $json.checklistResults.map(r => `INSERT INTO contract_schedule_checklist (contract_id, schedule_id, template_item_id, check_question, check_category, check_result, ai_evidence, ai_confidence) VALUES ('${$json.contractId}', '${$json.scheduleId}', ${r.template_item_id ? "'" + r.template_item_id + "'" : 'NULL'}, '${r.check_question.replace(/'/g, "''")}', '${r.check_category}', '${r.check_result}', '${(r.ai_evidence || '').replace(/'/g, "''")}', ${r.ai_confidence});`).join('\n') : '-- No results to insert' }}

-- Update schedule with checklist status and score
UPDATE contract_schedules
SET checklist_status = 'complete',
    checklist_score = {{ $json.checklistScore !== null ? $json.checklistScore : 'NULL' }}
WHERE schedule_id = '{{ $json.scheduleId }}'::uuid;
